function esc(s){return (s||'').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
const j = items[0].json || {};
const wf = j.workflow || {};
const ex = j.execution || {};
const err = ex.error || j.error || {};
const node = err.node && err.node.name ? err.node.name : (err.lastNodeExecuted || '');
const msg = (err.message || err.description || 'Unknown error').toString();
const url = ex.url || '';

let html = `🎙️ <b>Podcast streaming — workflow failed</b>\n`;
html += `<i>${esc(wf.name || 'Podcast streaming')}</i>\n\n`;
if (node) html += `<b>Node:</b> ${esc(node)}\n`;
html += `<b>Error:</b> ${esc(msg.slice(0, 600))}\n`;
if (ex.mode) html += `<b>Mode:</b> ${esc(ex.mode)}\n`;
if (url) html += `\n<a href=\"${esc(url)}\">Open execution</a>`;

return [{ json: { telegramHtml: html } }];
